package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Collections;
import java.util.List;
import java.util.Objects;

import org.apache.datasketches.common.SketchesArgumentException;

/** Predicate over one OmniSketch dimension. */
public final class OmniSketchPredicate {
	/** Maximum number of integral values expanded by {@link #longRange(long, long)}. */
	public static final long MAX_EXPANDED_LONG_RANGE = 1_000_000L;

	private static final OmniSketchPredicate ALL = new OmniSketchPredicate(true, List.of(), null);

	private final boolean all;
	private final List<Object> values;
	private final long[] preHashedValues;

	private OmniSketchPredicate(final boolean all, final List<Object> values, final long[] preHashedValues) {
		this.all = all;
		this.values = Collections.unmodifiableList(values);
		this.preHashedValues = preHashedValues == null ? null : preHashedValues.clone();
		if (!all && this.values.isEmpty() && (this.preHashedValues == null || this.preHashedValues.length == 0)) {
			throw new SketchesArgumentException("An OmniSketch predicate must contain at least one value");
		}
	}

	/** Creates a predicate that matches every value in this dimension. */
	public static OmniSketchPredicate all() {
		return ALL;
	}

	/** Creates an equality predicate. */
	public static OmniSketchPredicate equalTo(final Object value) {
		final List<Object> values = new ArrayList<>(1);
		values.add(value);
		return new OmniSketchPredicate(false, values, null);
	}

	/** Alias for {@link #equalTo(Object)}. */
	public static OmniSketchPredicate of(final Object value) {
		return equalTo(value);
	}

	/** Creates a predicate matching null values. */
	public static OmniSketchPredicate isNull() {
		return equalTo(null);
	}

	/** Creates an equality predicate over a pre-hashed value hash. */
	public static OmniSketchPredicate equalToHash(final long valueHash) {
		return new OmniSketchPredicate(false, List.of(), new long[] { valueHash });
	}

	/** Creates an IN predicate. Values are interpreted as a union within one single-valued dimension. */
	public static OmniSketchPredicate in(final Collection<?> values) {
		if (values == null || values.isEmpty()) {
			throw new SketchesArgumentException("values must not be null or empty");
		}
		return new OmniSketchPredicate(false, new ArrayList<>(values), null);
	}

	/** Creates an IN predicate over long values. */
	public static OmniSketchPredicate anyOfLongs(final long... values) {
		Objects.requireNonNull(values, "values must not be null");
		if (values.length == 0) {
			throw new SketchesArgumentException("values must not be empty");
		}
		final List<Object> boxed = new ArrayList<>(values.length);
		for (final long value : values) {
			boxed.add(value);
		}
		return new OmniSketchPredicate(false, boxed, null);
	}

	/** Creates an IN predicate over strings. */
	public static OmniSketchPredicate anyOfStrings(final String... values) {
		Objects.requireNonNull(values, "values must not be null");
		if (values.length == 0) {
			throw new SketchesArgumentException("values must not be empty");
		}
		final List<Object> list = new ArrayList<>(values.length);
		Collections.addAll(list, values);
		return new OmniSketchPredicate(false, list, null);
	}

	/** Creates an IN predicate over pre-hashed value hashes. */
	public static OmniSketchPredicate anyOfHashes(final long... valueHashes) {
		Objects.requireNonNull(valueHashes, "valueHashes must not be null");
		if (valueHashes.length == 0) {
			throw new SketchesArgumentException("valueHashes must not be empty");
		}
		return new OmniSketchPredicate(false, List.of(), valueHashes);
	}

	/**
	 * Creates a predicate over an inclusive long range by expanding it to equality predicates.
	 *
	 * <p>
	 * This method is intended for small integral domains. It rejects very large ranges rather than creating an
	 * unexpectedly expensive predicate.
	 * </p>
	 */
	public static OmniSketchPredicate longRange(final long inclusiveLower, final long inclusiveUpper) {
		if (inclusiveUpper < inclusiveLower) {
			throw new SketchesArgumentException("inclusiveUpper must be >= inclusiveLower");
		}
		final long size = inclusiveUpper - inclusiveLower + 1L;
		if (size <= 0L || size > MAX_EXPANDED_LONG_RANGE) {
			throw new SketchesArgumentException("longRange expands at most " + MAX_EXPANDED_LONG_RANGE + " values");
		}
		final List<Object> values = new ArrayList<>((int) size);
		for (long value = inclusiveLower; value <= inclusiveUpper; value++) {
			values.add(value);
		}
		return new OmniSketchPredicate(false, values, null);
	}

	boolean isAll() {
		return all;
	}

	long[] valueHashes(final long seed) {
		if (preHashedValues != null) {
			return preHashedValues.clone();
		}
		final long[] hashes = new long[values.size()];
		for (int i = 0; i < values.size(); i++) {
			hashes[i] = OmniSketchHash.hashValue(values.get(i), seed);
		}
		return hashes;
	}

	/** Returns the number of literal or pre-hashed values in this predicate. */
	public int size() {
		return all ? 0 : (preHashedValues != null ? preHashedValues.length : values.size());
	}

	/** Returns true if this predicate is a single equality predicate. */
	public boolean isEquality() {
		return !all && size() == 1;
	}

	@Override
	public String toString() {
		if (all) {
			return "ALL";
		}
		if (preHashedValues != null) {
			return preHashedValues.length == 1 ? "HASH=" + Long.toUnsignedString(preHashedValues[0])
					: "HASH_IN[" + preHashedValues.length + ']';
		}
		return values.size() == 1 ? "=" + values.get(0) : "IN" + values;
	}
}
